parameters.jsCode:
const docs = $input.all();
const datos = $('When_Executed_by_Main_Workflow').first().json;

let contexto = '';
if (docs.length === 0 || !docs[0].json.contenido) {
  contexto = 'No se encontró información relevante en los documentos.';
} else {
  contexto = docs.map((d, i) => 
    `[Fuente ${i+1}] (similitud: ${(d.json.similarity * 100).toFixed(1)}%):\n${d.json.contenido}`
  ).join('\n\n');
}

return [{
  json: {
    ...datos,
    contexto
  }
}];

